messages.content:
RISKS:
[
 {
  "riskId": "risk.boundary-substitution.enterprise-gpu-busbar-half-refuted",
  "title": "The 'refuted' GPU-pod doubt was only half-refuted: dense enterprise AI refresh ships on DC busbar, hollowing seg.enterprise from both ends",
  "claim": "Refinement cycle 1 closed the 'GPU pods skip PDUs' doubt because NVIDIA reference architectures ship PDU variants. But the vendor publishes parallel architectures: the AC/PDU version is the fallback, while the flagship dense design routes power via DC busbar with materially lower PDU attach per rack. The only part of enterprise on-premise that is growing is exactly this GPU-pod build-out; the legacy base is bleeding ~2pp of capacity share per year toward 19% by 2031. So the 0.29 enterprise slice is squeezed twice — the shrinking legacy half keeps buying PDUs it already owns, and the growing AI half is steered toward the substitute. A checkbox marked 'confirmed' is carrying 29% of the TAM.",
  "falsifier": "Attach-rate evidence from 2026 CE enterprise GPU-pod deployments (integrator BOMs or vendor order data) showing rack-PDU counts per rack at or above the legacy ≥3-per-rack norm in the majority of dense installs."
 },
 {
  "riskId": "risk.boundary-substitution.colo-spec-contagion-from-hyperscale-tenants",
  "title": "Wholesale colocation inherits hyperscaler power specs: the 18% colo slice — modeled with zero sensitivity band — follows the substitute out of category",
  "claim": "The model treats colocation as the PDU-native safe harbor: seg.colocation carries a null sensitivity band, so it never appears in the tornado at all. But CBRE shows European colo take-up being outstripped by hyperscaler and AI/HPC tenant demand — and in wholesale/prelet halls the tenant, not the operator, dictates the rack power architecture. If hyperscale tenants specify busway plus power shelves inside leased halls (the same migration the exemplar tracks in self-build), the colo segment's PDU content leaves the category through the tenant spec sheet while the operator's capacity numbers keep growing 19% a year. The one segment the engine treats as certain is the one with the untracked contagion path.",
  "falsifier": "Fit-out specifications from 2026 CE wholesale colocation preleases (Frankfurt, Amsterdam) showing rack PDUs — tenant-supplied or operator-supplied — as the standard rack power distribution in AI-density halls rather than busway/shelf architectures."
 },
 {
  "riskId": "risk.boundary-substitution.ce7-hyperscale-mix-mirage",
  "title": "The 0.91 rescale imports hyperscale that isn't in CE-7: the segment mix is misallocated even though the TAM headline doesn't move",
  "claim": "seg.hyperscale applies Synergy's global 48% hyperscale capacity share to Central Europe via a flat 0.91 carve-out. But ~60% of Europe's operational hyperscale self-build capacity sits in Ireland, the Netherlands, Sweden and Belgium — three of the four outside CE-7 — and Europe's self-build growth (24% YoY) keeps landing disproportionately in those markets. CE-7 is structurally colo- and enterprise-weighted relative to the global mix the model borrowed. Because segment shares sum to the same base, the TAM headline is untouched and no alarm rings; but the SAM haircut logic, certification priorities and Year-1 pipeline are all built on a buyer mix that overweights hyperscale by perhaps a third. This is a resourcing kill, not a sizing kill.",
  "falsifier": "A Europe- or CE-scoped capacity split (CBRE, Synergy regional cut, or JLL) showing hyperscale-owned/operated capacity at ≥40% of CE-7 MW, validating the transplanted global share."
 },
 {
  "riskId": "risk.boundary-substitution.intelligent-subset-scope-mismatch",
  "title": "The venture sells intelligent PDUs; the TAM counts all rack PDUs — the category boundary mismatch is inside the model, not at its edge",
  "claim": "Every boundary discussion has focused on excluded substitutes (busway, shelves). The unexamined boundary is in the other direction: the product is intelligent rack PDUs, but tamBase is explicitly scoped as the 'Central Europe rack-PDU market, all segments/buyers' — including basic and metered-only units the venture does not sell. IndexBox itself maintains a separate EU 'Intelligent Rack PDUs' report distinct from its 'Rack PDUs' report, i.e., the industry's own taxonomy treats these as different products. No retrieved source states the intelligent share of European rack-PDU revenue, and the 10–12% intelligent growth figure the model cites traces to a far broader power-and-cable-management report. The ±40% band prices measurement error on the whole category; it says nothing about what fraction of that category the venture can even quote into. Both errors stack.",
  "falsifier": "IndexBox EU Intelligent Rack PDUs headline (or the Omdia rack-PDU tracker's segmentation) showing intelligent/managed units at ≥80% of EU rack-PDU revenue, confirming the subset ≈ category in value terms."
 },
 {
  "riskId": "risk.boundary-substitution.nl-selfbuild-hollows-second-geography",
  "title": "The best-triangulated geography is the trap: NL's 28% sits on a capped colo base while its growth migrates to self-build architectures a regional entrant can't quote into",
  "claim": "geo.NL is the model's most reassuring node — Statista and the Dutch Data Center Association agree within 3%. But that triangulation validates yesterday's colocation stock, not the composition of forward demand. The Netherlands is one of four countries holding ~60% of Europe's hyperscale self-build capacity, and self-build is growing 24% YoY versus colo's 19% — while Amsterdam (≈70% of NL colo) is supply-constrained. So the venture's second-largest geography weight (28% of the base) rests on a slice where the PDU-native part is capped and the growing part procures through hyperscaler global frameworks and busway/shelf architectures that a pre-launch regional entrant cannot reach in its first 12 months. The MW totals will keep rising; the biddable NL demand won't.",
  "falsifier": "2026 NL capacity-addition evidence (DDCA annual report plus fit-out tenders) showing new Dutch MW — including hyperscale campuses — specifying rack PDUs procured through channels open to regional vendors at rates proportional to NL's 28% weight."
 }
]

Emit JSON: { items: [{riskId, queries: [{query, kind: confirming|falsifying|base-rate}]}] } — 3 queries per risk.
